import { describe, it, expect } from "vitest";
import type { ModelMessage } from "ai";
import type {
  Message,
  CheckpointMessage,
  SessionMetadata,
  CompactionConfig,
  PruningConfig,
  ContinuationVariant,
  CompactionResult,
  PreparedCompactionV2,
  ActualTokenUsage,
  ActualTokenUsageInput,
  ContextUsage,
  TodoItem,
  StructuredState,
  SessionHeaderLine,
  MessageLine,
  CheckpointLine,
  SessionFileLine,
  CompactionSummary,
  CompactionSegment,
  PreparedCompactionSegment,
  PreparedCompaction,
} from "./compaction-types";

describe("compaction-types", () => {
  // --- Message (forward declaration) ---
  describe("Message", () => {
    it("should have required fields", () => {
      const message: Message = {
        createdAt: new Date(),
        id: "msg-123",
        modelMessage: { role: "user", content: "Hello" } as ModelMessage,
      };
      expect(message.createdAt).toBeInstanceOf(Date);
      expect(message.id).toBe("msg-123");
      expect(message.modelMessage).toBeDefined();
    });

    it("should allow optional originalContent", () => {
      const message: Message = {
        createdAt: new Date(),
        id: "msg-123",
        modelMessage: { role: "user", content: "Hello" } as ModelMessage,
        originalContent: "original",
      };
      expect(message.originalContent).toBe("original");
    });
  });

  // --- CheckpointMessage ---
  describe("CheckpointMessage", () => {
    it("should have required fields", () => {
      const checkpoint: CheckpointMessage = {
        createdAt: Date.now(),
        id: "cp-123",
        isSummary: false,
        message: { role: "user", content: "Test" } as ModelMessage,
      };
      expect(checkpoint.createdAt).toBeDefined();
      expect(checkpoint.id).toBeDefined();
      expect(typeof checkpoint.isSummary).toBe("boolean");
      expect(checkpoint.message).toBeDefined();
    });

    it("should allow optional isSummaryMessage", () => {
      const checkpoint: CheckpointMessage = {
        createdAt: Date.now(),
        id: "cp-123",
        isSummary: false,
        isSummaryMessage: true,
        message: { role: "user", content: "Test" } as ModelMessage,
      };
      expect(checkpoint.isSummaryMessage).toBe(true);
    });

    it("should allow optional originalContent", () => {
      const checkpoint: CheckpointMessage = {
        createdAt: Date.now(),
        id: "cp-123",
        isSummary: false,
        message: { role: "user", content: "Test" } as ModelMessage,
        originalContent: "original",
      };
      expect(checkpoint.originalContent).toBe("original");
    });
  });

  // --- SessionMetadata ---
  describe("SessionMetadata", () => {
    it("should have all required fields", () => {
      const metadata: SessionMetadata = {
        completionTokens: 100,
        createdAt: Date.now(),
        promptTokens: 200,
        sessionId: "session-123",
        summaryMessageId: null,
        updatedAt: Date.now(),
      };
      expect(metadata.completionTokens).toBe(100);
      expect(metadata.promptTokens).toBe(200);
      expect(metadata.sessionId).toBe("session-123");
      expect(metadata.summaryMessageId).toBeNull();
      expect(metadata.createdAt).toBeDefined();
      expect(metadata.updatedAt).toBeDefined();
    });

    it("should allow non-null summaryMessageId", () => {
      const metadata: SessionMetadata = {
        completionTokens: 100,
        createdAt: Date.now(),
        promptTokens: 200,
        sessionId: "session-123",
        summaryMessageId: "summary-456",
        updatedAt: Date.now(),
      };
      expect(metadata.summaryMessageId).toBe("summary-456");
    });
  });

  // --- CompactionConfig ---
  describe("CompactionConfig", () => {
    it("should allow empty config (all optional)", () => {
      const config: CompactionConfig = {};
      expect(config).toEqual({});
    });

    it("should allow optional contextLimit", () => {
      const config: CompactionConfig = { contextLimit: 128000 };
      expect(config.contextLimit).toBe(128000);
    });

    it("should allow optional enabled", () => {
      const config: CompactionConfig = { enabled: true };
      expect(config.enabled).toBe(true);
    });

    it("should allow optional getStructuredState", () => {
      const config: CompactionConfig = {
        getStructuredState: () => "state" || undefined,
      };
      expect(typeof config.getStructuredState).toBe("function");
    });

    it("should allow optional keepRecentTokens", () => {
      const config: CompactionConfig = { keepRecentTokens: 2000 };
      expect(config.keepRecentTokens).toBe(2000);
    });

    it("should allow optional maxTokens", () => {
      const config: CompactionConfig = { maxTokens: 8000 };
      expect(config.maxTokens).toBe(8000);
    });

    it("should allow optional reserveTokens", () => {
      const config: CompactionConfig = { reserveTokens: 2000 };
      expect(config.reserveTokens).toBe(2000);
    });

    it("should allow optional speculativeStartRatio", () => {
      const config: CompactionConfig = { speculativeStartRatio: 0.5 };
      expect(config.speculativeStartRatio).toBe(0.5);
    });

    it("should allow optional summarizeFn", () => {
      const config: CompactionConfig = {
        summarizeFn: async (messages) => "summary",
      };
      expect(typeof config.summarizeFn).toBe("function");
    });

    it("should allow optional thresholdRatio", () => {
      const config: CompactionConfig = { thresholdRatio: 0.5 };
      expect(config.thresholdRatio).toBe(0.5);
    });

    it("should allow all fields together", () => {
      const config: CompactionConfig = {
        contextLimit: 128000,
        enabled: true,
        getStructuredState: () => "state",
        keepRecentTokens: 2000,
        maxTokens: 8000,
        reserveTokens: 2000,
        speculativeStartRatio: 0.5,
        summarizeFn: async (msgs) => "summary",
        thresholdRatio: 0.5,
      };
      expect(config.contextLimit).toBe(128000);
      expect(config.enabled).toBe(true);
      expect(config.keepRecentTokens).toBe(2000);
      expect(config.maxTokens).toBe(8000);
      expect(config.reserveTokens).toBe(2000);
      expect(config.speculativeStartRatio).toBe(0.5);
      expect(config.thresholdRatio).toBe(0.5);
    });
  });

  // --- PruningConfig ---
  describe("PruningConfig", () => {
    it("should allow empty config (all optional)", () => {
      const config: PruningConfig = {};
      expect(config).toEqual({});
    });

    it("should allow optional eagerPruneToolNames", () => {
      const config: PruningConfig = { eagerPruneToolNames: ["tool1", "tool2"] };
      expect(config.eagerPruneToolNames).toEqual(["tool1", "tool2"]);
    });

    it("should allow optional enabled", () => {
      const config: PruningConfig = { enabled: true };
      expect(config.enabled).toBe(true);
    });

    it("should allow optional minSavingsTokens", () => {
      const config: PruningConfig = { minSavingsTokens: 200 };
      expect(config.minSavingsTokens).toBe(200);
    });

    it("should allow optional protectedToolNames", () => {
      const config: PruningConfig = { protectedToolNames: ["protected1"] };
      expect(config.protectedToolNames).toEqual(["protected1"]);
    });

    it("should allow optional protectRecentTokens", () => {
      const config: PruningConfig = { protectRecentTokens: 2000 };
      expect(config.protectRecentTokens).toBe(2000);
    });

    it("should allow optional replacementText", () => {
      const config: PruningConfig = { replacementText: "[pruned]" };
      expect(config.replacementText).toBe("[pruned]");
    });
  });

  // --- ContinuationVariant ---
  describe("ContinuationVariant", () => {
    it("should allow 'manual'", () => {
      const variant: ContinuationVariant = "manual";
      expect(variant).toBe("manual");
    });

    it("should allow 'auto-with-replay'", () => {
      const variant: ContinuationVariant = "auto-with-replay";
      expect(variant).toBe("auto-with-replay");
    });

    it("should allow 'tool-loop'", () => {
      const variant: ContinuationVariant = "tool-loop";
      expect(variant).toBe("tool-loop");
    });

    it("should not allow invalid values", () => {
      // TypeScript compile-time check - if this compiles, the type is correct
      const validVariants: ContinuationVariant[] = [
        "manual",
        "auto-with-replay",
        "tool-loop",
      ];
      expect(validVariants).toHaveLength(3);
    });
  });

  // --- CompactionResult ---
  describe("CompactionResult", () => {
    it("should have required fields", () => {
      const result: CompactionResult = {
        success: true,
        tokensAfter: 5000,
        tokensBefore: 10000,
      };
      expect(result.success).toBe(true);
      expect(result.tokensAfter).toBe(5000);
      expect(result.tokensBefore).toBe(10000);
    });

    it("should allow optional continuationVariant", () => {
      const result: CompactionResult = {
        success: true,
        tokensAfter: 5000,
        tokensBefore: 10000,
        continuationVariant: "manual",
      };
      expect(result.continuationVariant).toBe("manual");
    });

    it("should allow optional reason", () => {
      const result: CompactionResult = {
        success: false,
        tokensAfter: 10000,
        tokensBefore: 10000,
        reason: "No messages to compact",
      };
      expect(result.reason).toBe("No messages to compact");
    });

    it("should allow optional summaryMessageId", () => {
      const result: CompactionResult = {
        success: true,
        tokensAfter: 5000,
        tokensBefore: 10000,
        summaryMessageId: "summary-123",
      };
      expect(result.summaryMessageId).toBe("summary-123");
    });
  });

  // --- PreparedCompactionV2 ---
  describe("PreparedCompactionV2", () => {
    it("should have required fields", () => {
      const compaction: PreparedCompactionV2 = {
        baseMessageIds: ["msg-1", "msg-2"],
        revision: 1,
        splitIndex: 5,
        summaryText: "Summary of messages",
        tokenDelta: -5000,
      };
      expect(compaction.baseMessageIds).toHaveLength(2);
      expect(compaction.revision).toBe(1);
      expect(compaction.splitIndex).toBe(5);
      expect(compaction.summaryText).toBe("Summary of messages");
      expect(compaction.tokenDelta).toBe(-5000);
    });

    it("should allow optional replayMessage", () => {
      const compaction: PreparedCompactionV2 = {
        baseMessageIds: ["msg-1"],
        revision: 1,
        splitIndex: 5,
        summaryText: "Summary",
        tokenDelta: -5000,
